import{_ as a,o as s,c as i,a1 as t}from"./chunks/framework.BwhMLafE.js";const u=JSON.parse('{"title":"Benchmarks & Performance Methodology","description":"","frontmatter":{},"headers":[],"relativePath":"benchmarks.md","filePath":"benchmarks.md"}'),n={name:"benchmarks.md"};function r(o,e,l,h,c,d){return s(),i("div",null,[...e[0]||(e[0]=[t(`<h1 id="benchmarks-performance-methodology" tabindex="-1">Benchmarks &amp; Performance Methodology <a class="header-anchor" href="#benchmarks-performance-methodology" aria-label="Permalink to &quot;Benchmarks &amp; Performance Methodology&quot;">​</a></h1><h2 id="table-of-contents" tabindex="-1">Table of Contents <a class="header-anchor" href="#table-of-contents" aria-label="Permalink to &quot;Table of Contents&quot;">​</a></h2><ul><li><a href="#overview">Overview</a></li><li><a href="#running-benchmarks">Running Benchmarks</a></li><li><a href="#understanding-output-metrics">Understanding Output Metrics</a></li><li><a href="#reference-benchmark-results">Reference Benchmark Results</a></li><li><a href="#tips-for-reliable-measurement">Tips for Reliable Measurement</a></li></ul><hr><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Galley is engineered from the ground up to maximize parsing throughput. To accurately evaluate performance and verify zero-overhead assertions across different hardware, every generated executable includes built-in benchmarking profiling support.</p><hr><h2 id="running-benchmarks" tabindex="-1">Running Benchmarks <a class="header-anchor" href="#running-benchmarks" aria-label="Permalink to &quot;Running Benchmarks&quot;">​</a></h2><p>Always compile binaries with <code>-Doptimize=ReleaseFast</code> when measuring speed. Debug and ReleaseSafe builds include extensive safety checks and trace logging that significantly degrade throughput.</p><p>To execute a benchmark run, pass the target file along with the <code>-r</code> (<code>--iterations</code>) and <code>-w</code> (<code>--warmup-iterations</code>) flags:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Run 100 benchmark iterations with 10 warmup passes on large JSON input</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">zig</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -Doptimize=ReleaseFast</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ll-json</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -r</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 100</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -w</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 10</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> languages/json/samples/code-02.json</span></span></code></pre></div><hr><h2 id="understanding-output-metrics" tabindex="-1">Understanding Output Metrics <a class="header-anchor" href="#understanding-output-metrics" aria-label="Permalink to &quot;Understanding Output Metrics&quot;">​</a></h2><p>When invoked with <code>--verbosity 0</code> (the default), the parser executable prints a succinct benchmark summary to stdout:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Parsed 100 times in 6.5ms (avg: 65us) -&gt; ~722.7 MB/s</span></span></code></pre></div><ul><li><strong>Iterations (<code>Parsed N times</code>):</strong> The exact number of timed parse repetitions.</li><li><strong>Total &amp; Average Duration:</strong> Time elapsed across all timed iterations and average latency per parse pass.</li><li><strong>Throughput (<code>MB/s</code>):</strong> Calculated as <code>(FileSizeBytes * Iterations) / TotalTimeSeconds / 1_000_000</code>.</li></ul><p>When invoked with <code>--verbosity 1</code>, additional statistics regarding AST allocations and memory pool usage are reported alongside throughput:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>AST Nodes Allocated: 14,230</span></span>
<span class="line"><span>Node Pool Memory Footprint: 227.68 KB</span></span></code></pre></div><hr><h2 id="reference-benchmark-results" tabindex="-1">Reference Benchmark Results <a class="header-anchor" href="#reference-benchmark-results" aria-label="Permalink to &quot;Reference Benchmark Results&quot;">​</a></h2><p>For full benchmark results, see the <strong><a href="/galley/benchmark_results.html">Benchmark Results</a></strong> page. It includes per-grammar Galley measurements for JSON, Lisp, Lua, and Galley&#39;s own grammar format, plus a JSON-specific comparison against third-party parsers (simdjson, RapidJSON, Bison, LALRPOP, Nom, Tree-sitter).</p><hr><h2 id="tips-for-reliable-measurement" tabindex="-1">Tips for Reliable Measurement <a class="header-anchor" href="#tips-for-reliable-measurement" aria-label="Permalink to &quot;Tips for Reliable Measurement&quot;">​</a></h2><ol><li><strong>Always Use Warmup Passes (<code>-w 10</code>):</strong> Modern CPUs throttle clock speeds when idle. Warmup iterations prime instruction caches (L1i/L2) and force CPU governor frequency scaling before timing begins.</li><li><strong>Use Large Input Files:</strong> Parsing tiny files (&lt; 1 KB) measures OS timer precision resolution rather than parsing throughput. Use inputs of at least 100 KB to obtain stable metrics.</li><li><strong>Isolate Background Noise:</strong> Close CPU-heavy applications (browsers, background builds) during benchmark loops to minimize thread preemption variance.</li></ol>`,24)])])}const m=a(n,[["render",r]]);export{u as __pageData,m as default};
